import path from 'path';
import fs from 'fs';

const BASE_DIR = path.resolve('./public/content');

export default function handler(req, res) {
  const requestedPath = path.resolve(BASE_DIR, req.query.file);

  // Ensure resolved path is within the allowed base directory
  if (!requestedPath.startsWith(BASE_DIR)) {
    return res.status(403).json({ error: 'Access denied' });
  }

  // Proceed with file read
  const content = fs.readFileSync(requestedPath, 'utf8');
  res.send(content);
}

