// middleware.ts or login handler
function getSafeRedirectUrl(redirectParam: string | undefined): string {
  const DEFAULT_REDIRECT = '/dashboard';

  if (!redirectParam) return DEFAULT_REDIRECT;

  try {
    // Only allow relative paths
    if (redirectParam.startsWith('/') && !redirectParam.startsWith('//')) {
      // Validate it's a known safe path
      const url = new URL(redirectParam, 'https://neon.tech');
      if (url.hostname === 'neon.tech') {
        return url.pathname + url.search;
      }
    }
  } catch {
    // Invalid URL
  }

  return DEFAULT_REDIRECT;
}

